SELECT t, Name, sum(ValueRate) AS ValueRateAgg FROM (  SELECT t, Name, SubName, Value / (t/1000 - lagInFrame(t/1000,1,0) OVER ()) AS ValueRate  FROM (   SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, Name, if(today() % 2, 'subTest1', 'subTest2') AS SubName, max(Value) AS Value   FROM default.test_grafana WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706)   GROUP BY Name, SubName, t    ORDER BY Name, SubName, t  ) ) GROUP BY Name, t ORDER BY Name, t